                l2 = newNode;
                current2 = l2;
            } else {
                current2->next = newNode;
                current2 = current2->next;
            }
        }

        Node* result = addTwoNumbers(l1, l2);
        while (result != NULL) {
            printf("%d ", result->data);
            result = result->next;
        }
        printf("\n");
    }
    return 0;
}

